import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import ProductCard from '../components/ProductCard';
import { products, categories } from '../api';

const Home = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [productsList, setProductsList] = useState([]);
  const [brands, setBrands] = useState([]);
  const [selectedBrand, setSelectedBrand] = useState(searchParams.get('brand') || '');
  const [searchQuery, setSearchQuery] = useState(searchParams.get('name') || '');

  useEffect(() => {
    const brand = searchParams.get('brand');
    const name = searchParams.get('name');
    setSelectedBrand(brand || '');
    setSearchQuery(name || '');

    const params = {};
    if (brand) params.brand = brand;
    if (name) params.name = name;

    products.getAll(params).then(res => {
      setProductsList(res.data);
      const uniqueBrands = [...new Set(res.data.map(p => p.brand))];
      setBrands(uniqueBrands);
    });
  }, [searchParams]);

  const handleBrandFilter = (brand) => {
    const newParams = new URLSearchParams(searchParams);
    if (brand) {
      newParams.set('brand', brand);
    } else {
      newParams.delete('brand');
    }
    setSearchParams(newParams);
    setSelectedBrand(brand);
  };

  const handleSearch = (e) => {
    const value = e.target.value;
    setSearchQuery(value);
    const newParams = new URLSearchParams(searchParams);
    if (value) {
      newParams.set('name', value);
    } else {
      newParams.delete('name');
    }
    setSearchParams(newParams);
  };

  return (
    <div>
      <motion.div 
        className="hero"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.6 }}
      >
        <div className="container">
          <motion.h1 
            initial={{ y: 30, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.2, duration: 0.5 }}
          >
            Xush kelibsiz!
          </motion.h1>
          <motion.p 
            initial={{ y: 30, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.3, duration: 0.5 }}
          >
            Eng sifatli mahsulotlar eng arzon narxlarda
          </motion.p>
          <motion.div
            initial={{ y: 30, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.5 }}
          >
            <Link to="/products" className="btn">Mahsulotlarni ko'rish</Link>
          </motion.div>
        </div>
      </motion.div>

      <div className="container" style={{ paddingBottom: '48px' }}>
        <motion.div 
          className="search-container"
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          transition={{ delay: 0.5 }}
        >
          <img src="https://img.icons8.com/ios/50/2c3e50/search--v1.png" alt="Search" className="search-icon" />
          <input
            type="text"
            className="search-input"
            placeholder="Mahsulotlarni qidirish..."
            value={searchQuery}
            onChange={handleSearch}
          />
        </motion.div>

        {brands.length > 0 && (
          <motion.div 
            className="brand-filters"
            initial={{ y: 20, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ delay: 0.6 }}
          >
            <button 
              className={`brand-btn ${!selectedBrand ? 'active' : ''}`}
              onClick={() => handleBrandFilter('')}
            >
              Hammasi
            </button>
            {brands.map(brand => (
              <button
                key={brand}
                className={`brand-btn ${selectedBrand === brand ? 'active' : ''}`}
                onClick={() => handleBrandFilter(brand)}
              >
                {brand}
              </button>
            ))}
          </motion.div>
        )}

        <motion.h2 
          className="section-title"
          initial={{ x: -20, opacity: 0 }}
          animate={{ x: 0, opacity: 1 }}
          transition={{ delay: 0.7 }}
        >
          Yangi mahsulotlar
        </motion.h2>

        <motion.div 
          className="products-grid"
          layout
        >
          <AnimatePresence mode="popLayout">
            {productsList.slice(0, 8).map((product, index) => (
              <motion.div
                key={product.id}
                layout
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.8 }}
                transition={{ delay: index * 0.05 }}
              >
                <ProductCard product={product} />
              </motion.div>
            ))}
          </AnimatePresence>
        </motion.div>

        {productsList.length > 8 && (
          <div style={{ textAlign: 'center', marginTop: '32px' }}>
            <Link to="/products" className="btn btn-secondary">Barcha mahsulotlar</Link>
          </div>
        )}
      </div>
    </div>
  );
};

export default Home;
